CREATE DATABASE IF NOT EXISTS flowmind_agent DEFAULT CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci;
USE flowmind_agent;
CREATE TABLE sys_user (id BIGINT PRIMARY KEY AUTO_INCREMENT, username VARCHAR(64) NOT NULL, password VARCHAR(128) NOT NULL, nickname VARCHAR(64), avatar VARCHAR(255), status TINYINT DEFAULT 1, created_at DATETIME DEFAULT CURRENT_TIMESTAMP, updated_at DATETIME DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP, deleted TINYINT DEFAULT 0);
CREATE TABLE sys_role (id BIGINT PRIMARY KEY AUTO_INCREMENT, role_code VARCHAR(64), role_name VARCHAR(64), created_at DATETIME DEFAULT CURRENT_TIMESTAMP, updated_at DATETIME DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP, deleted TINYINT DEFAULT 0);
CREATE TABLE sys_user_role (id BIGINT PRIMARY KEY AUTO_INCREMENT, user_id BIGINT, role_id BIGINT, created_at DATETIME DEFAULT CURRENT_TIMESTAMP, updated_at DATETIME DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP, deleted TINYINT DEFAULT 0);
CREATE TABLE agent_session (id BIGINT PRIMARY KEY AUTO_INCREMENT, user_id BIGINT, agent_type VARCHAR(64), title VARCHAR(128), created_at DATETIME DEFAULT CURRENT_TIMESTAMP, updated_at DATETIME DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP, deleted TINYINT DEFAULT 0);
CREATE TABLE agent_message (id BIGINT PRIMARY KEY AUTO_INCREMENT, session_id BIGINT, role VARCHAR(32), content TEXT, cards JSON, created_at DATETIME DEFAULT CURRENT_TIMESTAMP, updated_at DATETIME DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP, deleted TINYINT DEFAULT 0);
CREATE TABLE prompt_template (id BIGINT PRIMARY KEY AUTO_INCREMENT, agent_type VARCHAR(64), name VARCHAR(128), template TEXT, enabled TINYINT DEFAULT 1, created_at DATETIME DEFAULT CURRENT_TIMESTAMP, updated_at DATETIME DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP, deleted TINYINT DEFAULT 0);
CREATE TABLE knowledge_doc (id BIGINT PRIMARY KEY AUTO_INCREMENT, title VARCHAR(255), category VARCHAR(64), file_url VARCHAR(255), summary TEXT, source VARCHAR(64), created_at DATETIME DEFAULT CURRENT_TIMESTAMP, updated_at DATETIME DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP, deleted TINYINT DEFAULT 0);
CREATE TABLE knowledge_tag (id BIGINT PRIMARY KEY AUTO_INCREMENT, name VARCHAR(64), color VARCHAR(32), created_at DATETIME DEFAULT CURRENT_TIMESTAMP, updated_at DATETIME DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP, deleted TINYINT DEFAULT 0);
CREATE TABLE knowledge_doc_tag (id BIGINT PRIMARY KEY AUTO_INCREMENT, doc_id BIGINT, tag_id BIGINT, created_at DATETIME DEFAULT CURRENT_TIMESTAMP, updated_at DATETIME DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP, deleted TINYINT DEFAULT 0);
CREATE TABLE content_topic (id BIGINT PRIMARY KEY AUTO_INCREMENT, title VARCHAR(255), platform VARCHAR(64), topic_type VARCHAR(64), style VARCHAR(64), status VARCHAR(64), heat_score INT, favorite TINYINT DEFAULT 0, created_at DATETIME DEFAULT CURRENT_TIMESTAMP, updated_at DATETIME DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP, deleted TINYINT DEFAULT 0);
CREATE TABLE content_calendar (id BIGINT PRIMARY KEY AUTO_INCREMENT, topic_id BIGINT, publish_date DATE, channel VARCHAR(64), owner VARCHAR(64), status VARCHAR(64), created_at DATETIME DEFAULT CURRENT_TIMESTAMP, updated_at DATETIME DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP, deleted TINYINT DEFAULT 0);
CREATE TABLE student_profile (id BIGINT PRIMARY KEY AUTO_INCREMENT, name VARCHAR(64), gender VARCHAR(16), school VARCHAR(128), major VARCHAR(128), gpa DECIMAL(3,2), ranking VARCHAR(32), english_score VARCHAR(64), target_school VARCHAR(255), application_stage VARCHAR(64), risk_level VARCHAR(32), created_at DATETIME DEFAULT CURRENT_TIMESTAMP, updated_at DATETIME DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP, deleted TINYINT DEFAULT 0);
CREATE TABLE student_application_progress (id BIGINT PRIMARY KEY AUTO_INCREMENT, student_id BIGINT, stage VARCHAR(64), progress INT, note TEXT, created_at DATETIME DEFAULT CURRENT_TIMESTAMP, updated_at DATETIME DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP, deleted TINYINT DEFAULT 0);
CREATE TABLE school_info (id BIGINT PRIMARY KEY AUTO_INCREMENT, name VARCHAR(128), region VARCHAR(64), level VARCHAR(64), discipline_tags VARCHAR(255), created_at DATETIME DEFAULT CURRENT_TIMESTAMP, updated_at DATETIME DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP, deleted TINYINT DEFAULT 0);
CREATE TABLE school_project (id BIGINT PRIMARY KEY AUTO_INCREMENT, school_id BIGINT, project_name VARCHAR(255), project_type VARCHAR(64), deadline DATE, requirements TEXT, materials TEXT, source_url VARCHAR(255), created_at DATETIME DEFAULT CURRENT_TIMESTAMP, updated_at DATETIME DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP, deleted TINYINT DEFAULT 0);
CREATE TABLE feishu_sync_record (id BIGINT PRIMARY KEY AUTO_INCREMENT, sync_type VARCHAR(64), target_name VARCHAR(128), status VARCHAR(64), message TEXT, created_at DATETIME DEFAULT CURRENT_TIMESTAMP, updated_at DATETIME DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP, deleted TINYINT DEFAULT 0);
CREATE TABLE system_log (id BIGINT PRIMARY KEY AUTO_INCREMENT, module VARCHAR(64), level VARCHAR(32), message TEXT, trace_id VARCHAR(64), created_at DATETIME DEFAULT CURRENT_TIMESTAMP, updated_at DATETIME DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP, deleted TINYINT DEFAULT 0);
